"""Protocol for optional API debug logging (raw response body)."""from __future__ import annotationsfrom typing import Any, Protocolclass ResponseLoggerProtocol(Protocol):    """    Опциональный логгер сырых ответов API.    Может быть не передан (None) и тогда не используется. Контракт — debug(),    как в IExtensionLogger (extension.logger.logger_protocol).    """    def debug(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...__all__ = ["ResponseLoggerProtocol"]